package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlinx.coroutines.channels.*
import kotlin.test.*

class SharedFlowToListTest : TestBase() {

    @Test
    fun testToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(acc)
        }

        yield() // Give the collection time to start

        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        yield() // Give the collection time to process

        job.cancelAndJoin()

        assertEquals(listOf(1, 2, 3), acc)
    }

    @Test
    fun testToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableSetOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toSet(acc)
        }

        yield() // Give the collection time to start

        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(1) // Duplicate should be handled by Set
        sharedFlow.emit(3)

        yield() // Give the collection time to process

        job.cancelAndJoin()

        assertEquals(setOf(1, 2, 3), acc)
    }

    @Test
    fun testToListCollectsAllEmissions() = runTest {
        val sharedFlow = MutableSharedFlow<String>()
        val acc = mutableListOf<String>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(acc)
        }

        yield()

        sharedFlow.emit("a")
        sharedFlow.emit("b")
        sharedFlow.emit("c")
        sharedFlow.emit("d")

        yield()

        job.cancelAndJoin()

        assertContentEquals(listOf("a", "b", "c", "d"), acc)
    }
}
